INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028542e3c98b09417660d2', '非常推荐，博物馆值得看看', '["https://dimg04.c-ctrip.com/images/0235h12000i6bi01d1F66_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000i6a56gy63A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000i6biq6s3D6F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-30', '花园双床房', '双床房', '家庭亲子', 12, 0, 8, 4, '["整体满意度","周边配套"]'::jsonb, '整体满意度', '周边配套', NULL),
('68028542e3c98b09417660d4', '二次入住，这次时间比较宽裕，更好体验酒店服务和设施，前台betty专业，服务热情，客服服务及时热情，餐厅也好吃。', '["https://dimg04.c-ctrip.com/images/0233m12000jecsol8C24A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000jeca3s17FFA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-29', '花园双床房', '双床房', '朋友出游', 56, 0, 8, 6, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68028542e3c98b09417660d5', '大堂装修豪华，服务到位，非常舒适', '["https://dimg04.c-ctrip.com/images/0235112000ifpqrjvE842_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231x12000ifpqxhy4FAF_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231d12000ifpqv1a08F5_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-10', '花园双床房', '双床房', '家庭亲子', 16, 0, 12, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68028542e3c98b09417660d6', '来广州首选花园酒店，住过好几次了还是非常满意！工作人员热情有礼，感谢Cecilia和Gillian，看到我们带小孩就给我们免费升级了房间～房间干净整洁，早餐品种比较丰富，味道很不错的。', '["https://dimg04.c-ctrip.com/images/0236b12000faxc77w62A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000faxaxonC3BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000faxd2jj4E46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000faxd2jl8132_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-30', '花园大床房', '大床房', '家庭亲子', 92, 0, 23, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68028542e3c98b09417660d7', '作为广州本地人，我偶尔住酒店换换心情，常住的是MO，这次换了花园酒店，很是惊喜。花园是广州最老牌的五星酒店，改革开放后算是广州地标了，本地人无人不知，那时是外宾住的，当时还没有四季瑰丽MO。十年前，装修前我也住过，体验也不错。这次是装修后，升级了红棉套房，房间大，设计合理，床垫舒适，按这个价格来说，性价比极高了。服务方面，所有服务人员都很热情，有笑容，尤其多了很多印度服务生，那态度更好，笑得也灿烂。基本上，客人的要求有求必应，服务专业周到，我离开酒店遗漏钱包在保险柜，也马上联系，妥善处理，可以体会出来是正宗五星酒店的服务水平。早餐，4个餐厅，吃的也好。总体来说，这是家有品位，有品质，有文化底蕴的五星酒店，值得！', '["https://dimg04.c-ctrip.com/images/0231d12000f5lrv509B8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-17', '城央绿意大床房', '大床房', '其他', 309, 0, 8, 9, '["整体满意度","性价比","房间设施"]'::jsonb, '整体满意度', '性价比', '房间设施'),
('68028542e3c98b09417660d8', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包括久负盛名的四季、丽思卡尔顿、白天鹅等等，这次花园酒店给我的感受是最棒的，酒店建成虽然年代久了，但是各种细节一点也不马虎，房间灯光的设计恰到好处，不亮也不暗；家具布置使用方便舒适；早餐的每个餐桌都有鲜花；每一个喷泉都干净清洁且保持流水状态；恰逢周一，我还碰到了酒店博物馆闭馆日在按惯例清洁水池，以上所有这些细节都看的出酒店的管理和运作非常良好。酒店四楼的博物馆完全超出了我的想象，开始以为会是一个简单的展示，但其实非常专业，很值得一看。餐厅出品也非常棒，在荔湾亭吃了两顿饭，出品很不错，服务人员会主动告诉我怎么点餐最划算；泳池水干净清澈，配备的救生人员也足够数量，各个角度都能覆盖；酒店大堂富丽堂皇又有底蕴；瀑布和花园的亭台楼阁完美的体现着岭南的风貌。给我办理入住的吴经理，看到我定了前后日期相连的两个订单，一个是普通的花园房，一个是粤韵房，主动帮我把前两天的房间也给升级成了粤韵房，避免我要更换房间的麻烦；入住第二天咨询前台人员，准备购买酒店早餐，前台的Ann小姐特别Nice,见我就是一个人带个五岁小朋友，直接免了早餐，更把后面两天要来会合的孩子爸爸早餐也给送了；离开前一天下午到酒店行政酒廊看看风景喝点东西，行政酒廊的每一位小姐姐都非常亲切周到，主动提供各种信息和服务，其中一位Kitty小姐姐贴心热情的邀请我们第二天一早来酒廊用早餐。入住期间提出的所有要求都及时响应，每天都会送上水果和小食，房间打扫及时卫生，遇到的每一位服务人员都热情耐心，感谢酒店所有人美声甜的小姐姐们和友善贴心的帅哥们，以及所有一丝不苟对品质有所坚持的管理者们，为你们的用心送上大大的赞，也希望能够保留这样的底蕴到地久天长。以后来广州不会再更换酒店了，一定是花园酒店！', '["https://dimg04.c-ctrip.com/images/0232s12000f3zjl9u3DDE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000f3zilnn631F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000f3zkz5140C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-13', '粤韵双床套房', '套房', '家庭亲子', 764, 0, 6, 10, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68028542e3c98b09417660d9', '原本对这家建造较早的酒店存有刻板印象，所以只作为备选，还订错了入住日期，在酒店前厅部郑经理热情耐心的远程协调下，不仅调整好日期，还获得了小惊喜。入住后，被酒店红红火火的年味、历史与现代的完美融合和小帅小美们暖暖的服务惊到了。2025的广州春节，为我们整个团队的小伙伴带来了开年好运！', '["https://dimg04.c-ctrip.com/images/0234s12000ibffb96112D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2025-02-05', '花园大床房', '大床房', '朋友出游', 141, 0, 3, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b09417660da', '相比卓美亚，这里完胜。首先这里窗外毫无景色，我相信选择老牌五星酒店不是为了窗外景色来的，一进酒店大堂所有人都会被那幅红楼梦黄金雕刻所吸引，大堂明亮宽敞，前台办理入住有条不紊，有空房直接升级，赞。大堂礼宾服务周到，人多的时候始终有服务员帮客人按电梯，服务质量和人员完胜卓美亚十条街。房间都重新翻新过，古朴典雅、并且是套房你也敢相信，房间隔音还算不错，只是门不怎么隔音，洗漱用品也升级过了，床品也不错。楼下四家米其林餐厅实在是没机会品尝，下一次一定尝试，酒店内有的园林很不错，瀑布很高，很适合吃完饭在酒店里逛一逛。卫生我唯一没给满分的原因就是泳池的水有些浑浊，不如卓美亚的，不过其他几乎都是优点了，尤其很多航司都在这里过夜，看到阿航的姑娘们的确很美。还会再来', '["https://dimg04.c-ctrip.com/images/0230k12000f4u6p3u8101_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000f4uf75z1AD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000f4uhkm7E654_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000f4ugjx341B4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-15', '红棉双床套房', '套房', '家庭亲子', 327, 0, 20, 9, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68028542e3c98b09417660db', '??酒店性价比很高，房间也非常干净，服务也很周到，酒店也特别有氛围感，特别有城市花园和小世外桃源的感觉，不愧是花园酒店～下次还会再选择这里的??', '["https://dimg04.c-ctrip.com/images/0230a12000fm11qurA336_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000fm141j609C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000fm12xs47164_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园双床房', '双床房', '家庭亲子', 72, 0, 10, 7, '["性价比","整体满意度","卫生状况"]'::jsonb, '性价比', '整体满意度', '卫生状况'),
('68028542e3c98b09417660dc', '一如既往的好，喜欢。床特别舒服。', '["https://dimg04.c-ctrip.com/images/0235612000heo2gvdA039_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000heobb4lAABE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000heo1cko8792_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-25', '花园大床房', '大床房', '商务出差', 16, 0, 65, 4, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68028542e3c98b09417660df', '来广州出差选择最多的酒店之一，设施设备维护妥当，床品的质量也不错，不足的地方在于健身房的设备老旧，只有部分器械做了更换，另外房间的淋浴房水压有点小。', '["https://dimg04.c-ctrip.com/images/0231c12000fgi9hls2CF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-09-08', '花园双床房', '双床房', '商务出差', 74, 0, 8, 8, '["房间设施","公共设施"]'::jsonb, '房间设施', '公共设施', NULL),
('68028542e3c98b09417660e0', '广州花园酒店入住体验极佳，设施先进，服务细致，卫生干净，环境宁静舒适，每个细节都彰显高品质，让人印象深刻。', '["https://dimg04.c-ctrip.com/images/0231012000gf9kkzq7121_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000gf9a9sj6DB3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000gfa70ee60D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-01', '花园双床房', '双床房', '家庭亲子', 53, 0, 3, 7, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68028542e3c98b09417660e1', '不愧是老牌五星酒店，贴心温暖，细致到让你无法想象：酒店有三个早餐厅，第一天是1楼的瀑布餐厅，享受大自然的美妙，第二天是顶楼的旋转餐厅，伏视高空美景，第三天是三楼的精致早茶。美味惊艳。
     楼层服务员：lili每天换这花样送惊喜', '["https://dimg04.c-ctrip.com/images/0234v12000eyrdteqEBF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000eyrpa1kA443_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-01', '花园双床房', '双床房', '家庭亲子', 116, 0, 15, 9, '["餐饮设施","客房服务","整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度'),
('68028542e3c98b09417660e2', '花园酒店名不虚传，大堂金碧辉煌，花园漂亮大气，餐饮美味，服务非常贴心，环境优美。尤其是30楼行政酒廊的Carrie服务非常周到，对小朋友很有耐心，细心，中文说的非常好?还有Aimee 和Echo美丽大方，热情好客，让客人有宾至如归的感觉，下次来广州还住这里！', '["https://dimg04.c-ctrip.com/images/0232q12000f6ih3mc70CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000f6ibrszC5D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000f6ihx0c953B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000f6iht3vB3F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000f6i2x9z2F2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000f6ict8k6C0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000f6icbrxEABA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000f6iekma69CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000f6i516q18D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-19', '花园大床房', '大床房', '家庭亲子', 129, 0, 3, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68028542e3c98b09417660e3', '谢谢，这次会议连着住1周，加上在花园第N次入住，前台Betty给升级。非常好', '["https://dimg04.c-ctrip.com/images/0230512000hlnuarn2E51_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-05', '花园大床房', '大床房', '商务出差', 38, 0, 96, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b09417660e4', '选择花园酒店，是一种情怀。
20年前，年幼的我第一次来到广州，就在花园酒店，其间的纸醉金迷震撼到我20年不忘。
20年后，我4岁的女儿第一次来广州，也想让她与我拥有同样的记忆。
特别感谢前台的viria小姐姐，大气的为我们升级了房型，红棉房的瀑布景观让这份美好的记忆再上一层楼，我本来只订了一晚，果断原房续住又加了两晚。
这些年国内国外住过很多酒店，但花园酒店会一直在我的推荐清单上。', '["https://dimg04.c-ctrip.com/images/0233z12000exo29618647_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000exnuusg2E55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000exobas7D5A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-29', '花园大床房', '大床房', '家庭亲子', 192, 0, 4, 9, '["前台服务","景观/朝向","整体满意度"]'::jsonb, '前台服务', '景观/朝向', '整体满意度'),
('68028542e3c98b09417660e5', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太nice了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。连着续订三晚', '["https://dimg04.c-ctrip.com/images/0234b12000exg82i57B94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000exg2opy42DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000exfzt0r32D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-28', '花园大床房', '大床房', '家庭亲子', 119, 0, 6, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68028542e3c98b09417660e6', '满意的体验，在广州无论自己度假还是接待朋友，都会首选花园酒店，服务，环境，酒店的活动空间都非常好，房间舒适温馨。', '["https://dimg04.c-ctrip.com/images/0232z12000g12q1srD50F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000g12mdpt5C19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000g12xuf85078_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-07', '花园大床房', '大床房', '其他', 56, 0, 125, 7, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68028542e3c98b09417660e8', '这次入住的房间非常干净，窗外景观不错，位置优越，交通便利，入住体验非常好，前台张荣荣服务态度也很好，帮忙处理了续住等小事情，周到细心很热情，不错，推荐。', '["https://dimg04.c-ctrip.com/images/0230212000fgfa42nC144_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000fgezcjvD40E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000fgeqpik3BA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-08', '花园大床房', '大床房', '商务出差', 76, 0, 104, 8, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028542e3c98b09417660ec', '菜品和服务都不错，房间也可以的', '["https://dimg04.c-ctrip.com/images/0235e12000h9b31qsF99F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-18', '花园双床房', '双床房', '家庭亲子', 15, 0, 18, 4, '["餐饮设施","前台服务","房间设施"]'::jsonb, '餐饮设施', '前台服务', '房间设施'),
('68028542e3c98b09417660f4', '每次出差都会选择入住广州花园酒店，房间非常干净，舒适，整洁。Lavinia 帮助我快速办理入住，而且安排非常好，行政酒廊Cathy,Beryle.Kanchan,三位的服务很细致，值得体验一下，退房收到Kitty的问候，询问我入住感受，非常满意的一次体验，下次还会选择花园～满分好评', '["https://dimg04.c-ctrip.com/images/0234612000f91tozq364B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000f91kuaj689C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000f91wckb017F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-25', '花园大床房', '大床房', '商务出差', 141, 0, 125, 9, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68028542e3c98b09417660f5', '服务：超级好，MANCY很细心，很认真。
环境：大厅环境让人眼前一亮，房间环境也很好，床很舒服，枕头软软的。
卫生：很干净，没有异味
设施：2019年重新翻修了的，我们住的粤韵。
打车很方便
之前本来定了2天晚上，后来又续住两天，为我们免费升级了房间，有欢迎的甜点
还送了我们小礼品。', '["https://dimg04.c-ctrip.com/images/0230c12000evej4wg7930_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000evemllhCB60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000evejljrF4D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000even80qE7FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000evewaerF428_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000evemxnc1573_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000evem7tx9678_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-23', '花园双床房', '双床房', '独自旅行', 142, 0, 7, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028542e3c98b09417660f6', '装修后的花园酒店红棉套房非常舒适，干净卫生，30楼的行政楼旋转餐厅早餐品种很丰富，环境舒服，服务人员态度很好，值得推荐', '["https://dimg04.c-ctrip.com/images/0235612000gt7cwmpE6F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000gt7o63dFC20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000gt7c55s9C35_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-22', '红棉双床套房', '套房', '家庭亲子', 59, 0, 7, 8, '["整体满意度","餐饮设施","卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况'),
('68028542e3c98b09417660f7', '后花园和博物馆非常适合小孩游玩！', '["https://dimg04.c-ctrip.com/images/0231r12000iceo5bkC1F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000icebic1416E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '红棉双床套房', '套房', '家庭亲子', 16, 0, 14, 4, '["周边配套"]'::jsonb, '周边配套', NULL, NULL),
('68028542e3c98b09417660f8', '每次出差都会选择入住广州花园酒店，房间非常干净，舒适，整洁。前台Justin帮助我快速办理入住，行政酒廊的Carrie和Cathy服务很细心，退房收到lavinia的问候，询问我入住感受，非常满意的一次体验，下次还会选择花园～满分好评', '["https://dimg04.c-ctrip.com/images/0230m12000evtkjzyBF06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000evtj6a264C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000evtq7zm6046_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-24', '花园大床房', '大床房', '独自旅行', 117, 0, 125, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68028542e3c98b09417660f9', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了金卡会员号，前台没有任何关于金卡会员的介绍。客房没升级、免费早餐也不提、酒廊礼遇还是在我特意询问后才给了一张一个人的礼遇卡。什么欢迎水果，入住三天毛都没看见。我也是开了眼了！
但是酒店装潢很漂亮，公共设施维护很好。只是客房卫生间反味，房型过于紧凑。给娃买了毛绒纪念品，小姐姐得知我们不用开发票直接给我个人微信二维码让我缴费……呵呵了…', '["https://dimg04.c-ctrip.com/images/0230i12000etzfo8nD94A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000etzz3gl451D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000etzwb062F56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000etzviutC344_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-07-19', '花园双床房', '双床房', '家庭亲子', 207, 0, 2, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028542e3c98b09417660fa', '设施：虽然是85年的酒店但是保养的还真不错。走廊都没什么异味，只是房间小了点，地板有几块咯吱哇吱响。
卫生：打扫的蛮干净的，就是在抽屉拉手上有灰尘。
环境：周围很多大大小小的餐厅，酒店里也有四家米其林，早餐也很丰盛。
服务：入住办理迅速，每层楼都有服务生迎接，早餐餐厅、行政酒廊及桃园的服务都蛮好的。
尊享行政礼遇（含下午茶及欢乐时光-用餐地点锦鲤酒吧行政酒廊）:餐品丰富、服务热情、景观也很棒。
ps.很喜欢四楼的博物馆，专业级的。', '["https://dimg04.c-ctrip.com/images/0233i12000ej6jayxBA4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000ej6ln84C919_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000ej6mv92C967_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000ej6xhgb2FE1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000ej6pjfl6533_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000ej6pjfn4A96_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000ej6lizq43DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000ej6o2bo3725_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000ej6lk2lC820_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-20', '花园双床房', '双床房', '家庭亲子', 217, 0, 55, 9, '["整体满意度","周边配套","前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务'),
('68028542e3c98b09417660fb', '行政酒廊这边风景很好，而且这里的女孩子们服务态度都很好，很有礼貌，有什么需要随时提供帮助，carrie ，Aimee，cathy ，Beryle', '["https://dimg04.c-ctrip.com/images/0231p12000f61q7z1DF07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000f61lorc70FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-18', '花园双床房', '双床房', '商务出差', 72, 0, 71, 7, '["餐饮设施","前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL),
('68028542e3c98b09417660fc', '每次都是定这家，老人家在酒店可以吃个下午茶逛逛花园。', '["https://dimg04.c-ctrip.com/images/0235j12000gdr7x9j9676_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000gdqz2lfC47D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000gdrgn0s2E3B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-30', '花园双床房', '双床房', '商务出差', 26, 0, 14, 4, '["餐饮设施","公共设施"]'::jsonb, '餐饮设施', '公共设施', NULL),
('68028542e3c98b09417660fd', '服务态度很好 必须打卡花园酒店的经典早茶 设施也是翻新过 度过一个愉快的假期', '["https://dimg04.c-ctrip.com/images/0235q12000fxkmh716ADD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000fxk8xyw3298_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000fxk6ja1BF39_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-03', '花园双床房', '双床房', '家庭亲子', 38, 0, 10, 6, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68028542e3c98b09417660fe', '酒店大堂和房间都很漂亮，服务员也非常热情。小朋友玩得很开心。早餐下午茶也很优秀。', '["https://dimg04.c-ctrip.com/images/0232412000fzvfoqf1556_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000fzuxsh9FCEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000fzv3ij3CD8B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 40, 0, 14, 6, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68028542e3c98b09417660ff', '地理位置好，出行都很方便，而且团购的券也很划算，推荐大家来体验！是体验最好的一家店了，氛围很好，让人感觉很舒服??', '["https://dimg04.c-ctrip.com/images/0236g12000fc02qsn5484_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000fc03i5a2C12_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000fbzv24u4A62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000fbzkagy1814_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-31', '花园大床房', '大床房', '情侣出游', 57, 0, 27, 5, '["交通便利性","性价比","整体满意度"]'::jsonb, '交通便利性', '性价比', '整体满意度'),
('68028542e3c98b0941766100', '这次入住的房间非常干净，窗外景观不错，位置优越，交通便利，入住体验非常好，前台winnie wei服务态度也很好，帮忙处理了续住等小事情，周到细心很热情，不错，推荐。', '["https://dimg04.c-ctrip.com/images/0231x12000fh2tfvs7C7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000fh2ra6h468A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000fh2u44y17FF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-09-09', '花园大床房', '大床房', '商务出差', 83, 0, 104, 8, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028542e3c98b0941766101', '酒店环境很好，服务也很热情。接着续订了两晚，小孩玩得开心。早餐下午茶很好。', '["https://dimg04.c-ctrip.com/images/0230612000fzvkuzzB57D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000fzvu3xsF547_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000fzvskze464D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000fzvsn9n53FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000fzvqz5zF063_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000fzvx9dg96EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000fzvwvpoB815_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000fzvqrckABCB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 37, 0, 14, 5, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68028542e3c98b0941766102', '房间和服务都很一般', '["https://dimg04.c-ctrip.com/images/0236p12000gwyufz68B18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.6, 2, '2024-11-28', '花园双床房', '双床房', '商务出差', 9, 0, 12, 3, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68028542e3c98b0941766103', '酒店公共设施很好，服务也在线，房间稍显不足，早餐也没有达到预期', '["https://dimg04.c-ctrip.com/images/0232o12000g20hfdy5B07_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230912000g20gtdh09D6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231p12000g20i0e3728F_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231s12000g20igybC051_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-10-09', '花园双床房', '双床房', '其他', 31, 0, 47, 5, '["公共设施","前台服务","餐饮设施"]'::jsonb, '公共设施', '前台服务', '餐饮设施'),
('68028542e3c98b0941766104', '真的是很满意的一次入住，从进入酒店开始，每一个服务人员都超级贴心，前台小姐姐热情的帮我办理了入住，30楼的mignon aimee Carrie 从下午茶开始就热情并贴心的照顾我，服务超级棒????真心感谢????', '["https://dimg04.c-ctrip.com/images/0233l12000eidndpuCA3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000eidtk266E87_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000eiduiea9D2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000eidouyf141C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-18', '花园大床房', '大床房', '独自旅行', 107, 0, 21, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b0941766105', '酒店公共设施装修的很好，但是客房内部装修有点老，服务还是不错的，由于预订时房型没看清而选错，入住时前台再三提醒确认及时更改。希望酒店能够将客房内部装修再提升下，以后再来还会选择入住。', '["https://dimg04.c-ctrip.com/images/0236u12000elzu52wACED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000elzz8gnDB1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000elzzqu9B489_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-06-28', '花园大床房', '大床房', '家庭亲子', 91, 0, 10, 7, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68028542e3c98b0941766106', '设施：一流。
卫生：干净。
环境：古朴典雅。
服务：热情。前台员工对我的态度很好。主动帮我升级了房型。', '["https://dimg04.c-ctrip.com/images/0235q12000fg1ptsuD12A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000fg14z7dF84C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-07', '花园双床房', '双床房', '家庭亲子', 51, 0, 39, 6, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68028542e3c98b0941766107', '首先要感谢一下前台的Rebecca,帮我做了房间升级，每次来广州都会选择花园酒店，虽然酒店是最早一批的五星级酒店，但酒店后期有从新翻修过，整体房间设备都很好，酒店的服务也很好，也要感谢一下行政酒廊Carrie,跟她的伙伴们Deepa和Kanchan，她们整体服务真的很好，让你感觉分宾至如归的感觉，真心推荐给大家！！！', '["https://dimg04.c-ctrip.com/images/0233s224x8vbvo8npE745_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d224x8vbu8e1r42D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f224x8vburw49BAB6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-17', '花园大床房', '大床房', '商务出差', 159, 0, 30, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68028542e3c98b0941766108', '广州花园酒店的地理位置十分优越，紧邻市中心，交通便利，无论是商务出差还是休闲旅游，都能轻松抵达城市的各个角落。

步入酒店大堂，大堂的就是一整块刘姥姥进大观园，设计融合了传统与现代元素，展现出独特的艺术气息。前台工作人员的亲切问候和专业服务，让我从一开始就感受到了宾至如归的温暖。

房间内部的装饰同样令人印象深刻。家具布置考究，床品柔软舒适，保证了我每晚都能拥有高质量的睡眠。房间内的现代化设施一应俱全，高速的无线网络都极大地方便了我的工作和生活需求。

服务方面，广州花园酒店的每一位员工都展现出了高度的专业素养和热情周到。他们对客人的需求反应迅速，总是能够提供及时的帮助和解决方案，让我的住宿体验更加顺畅和愉快。特别是前台的Tony，处处能为客人考虑，很贴心。

总体来说，广州花园酒店以其优越的地理位置、典雅的装修风格、舒适的住宿环境、一流的餐饮服务以及专业的员工团队，为我提供了一次卓越的住宿体验。无论是商务出行还是休闲度假，我都会毫不犹豫地向朋友和家人推荐这家酒店，并期待在未来有机会再次入住。', '["https://dimg04.c-ctrip.com/images/0230p12000f2iidikE647_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000f2innvyFAE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000f2if60s30A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000f2imi8r4499_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000f2i8g3wC61A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000f2icmiq4D81_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000f2if60uED83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000f2iks497A36_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000f2iogdn19B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-10', '花园双床房', '双床房', '商务出差', 453, 0, 11, 9, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68028542e3c98b0941766109', '这次很庆幸定了花园酒店，不愧是白金五星 各方面品质在线，出行便利，下次来还会选择花园', '["https://dimg04.c-ctrip.com/images/0230r12000fixlsl6C503_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000fixa5tl3DD3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000fixvqlw3E05_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-12', '花园双床房', '双床房', '家庭亲子', 42, 0, 2, 6, '["整体满意度","交通便利性"]'::jsonb, '整体满意度', '交通便利性', NULL),
('68028542e3c98b094176610a', '酒店服务很好，地理位置优越。', '["https://dimg04.c-ctrip.com/images/0232b12000gjag89t323D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000gj9zbky492D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000gja72di5473_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-11-06', '花园大床房', '大床房', '商务出差', 14, 0, 111, 4, '["前台服务","交通便利性"]'::jsonb, '前台服务', '交通便利性', NULL),
